// HasEffect applies the HasEdge predicate on the "effect" edge.
func HasEffect() predicate.Trigger {
	return predicate.Trigger(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, EffectTable, EffectColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasEffectWith applies the HasEdge predicate on the "effect" edge with a given conditions (other predicates).
func HasEffectWith(preds ...predicate.Effect) predicate.Trigger {
	return predicate.Trigger(func(s *sql.Selector) {
		step := newEffectStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

